import { useEffect, useState } from "react";
import { animate, useMotionValue, useTransform, useReducedMotion } from "framer-motion";
import { fmt } from "@/lib/parseItem";

// Animated number that counts to a target and re-counts when target changes.
export function CountUp({ value, format = fmt, duration = 1.0, className = "", testId }) {
  const prefersReduced = useReducedMotion();
  const motion = useMotionValue(0);
  const formatted = useTransform(motion, (v) => format(Math.round(v)));
  const [display, setDisplay] = useState(() => prefersReduced ? format(value) : format(0));

  useEffect(() => {
    if (prefersReduced) {
      setDisplay(format(value));
      return;
    }
    const controls = animate(motion, value || 0, {
      duration,
      ease: [0.16, 1, 0.3, 1],
    });
    const unsub = formatted.on("change", (v) => setDisplay(v));
    return () => { controls.stop(); unsub(); };
  }, [value, duration, motion, formatted, format, prefersReduced]);

  return (
    <span className={`tabular ${className}`} data-testid={testId}>
      {display}
    </span>
  );
}

// Splits a price like "75.00M" — number then unit suffix colored separately.
export function PriceMorph({ value, className = "", numberClass = "", unitClass = "text-emerald-400" }) {
  const str = fmt(value);
  const match = str.match(/^([\d.,]+)([BMK]?)$/);
  if (!match) return <span className={`${className} tabular`}>{str}</span>;
  return (
    <span className={`${className} tabular`}>
      <span className={numberClass}>{match[1]}</span>
      {match[2] && <span className={unitClass}>{match[2]}</span>}
    </span>
  );
}
